    // Secure binding configuration
    public static class SecureBindingFactory
    {
        /// <summary>
        /// Creates a WS-Security compliant binding with strong encryption for HIPAA compliance.
        /// Uses AES-256 for symmetric encryption and RSA-OAEP for key wrapping.
        /// Enforces mutual certificate authentication and message-level security.
        /// </summary>
        public static CustomBinding CreateHipaaCompliantBinding()
        {
            // Use SecurityBindingElement for fine-grained control over WS-Security
            var securityElement = SecurityBindingElement.CreateMutualCertificateBindingElement(
                MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10);

            // Configure strong algorithm suite - AES256 with SHA256
            // This ensures:
            // - AES-256-CBC for symmetric encryption (message body)
            // - RSA-OAEP for asymmetric key wrapping
            // - SHA-256 for digest and signature
            // - HMAC-SHA256 for symmetric signature
            // - P-SHA1 with 256-bit key derivation
            securityElement.DefaultAlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            // Require encryption and signing of all message parts
            securityElement.SecurityHeaderLayout = SecurityHeaderLayout.Strict;
            securityElement.IncludeTimestamp = true;
            securityElement.MessageSecurityVersion = MessageSecurityVersion.WSSecurity11WSTrust13WSSecureConversation13WSSecurityPolicy12BasicSecurityProfile10;

            // Enable secure conversation for session-based encryption key management
            securityElement.SetKeyDerivation(true);

            // Require signed and encrypted security tokens
            securityElement.MessageProtectionOrder = MessageProtectionOrder.SignBeforeEncryptAndEncryptSignature;

            // Configure transport with TLS 1.2+ requirement
            var httpsTransport = new HttpsTransportBindingElement
            {
                RequireClientCertificate = true,
                MaxReceivedMessageSize = 1048576, // 1MB max to prevent DoS
                MaxBufferSize = 1048576
            };

            // Text message encoding with UTF-8
            var textEncoding = new TextMessageEncodingBindingElement
            {
                MessageVersion = MessageVersion.Soap12WSAddressing10,
                WriteEncoding = System.Text.Encoding.UTF8
            };

            // Set reader quotas to prevent XML bomb attacks
            textEncoding.ReaderQuotas.MaxDepth = 32;
            textEncoding.ReaderQuotas.MaxStringContentLength = 524288; // 512KB
            textEncoding.ReaderQuotas.MaxArrayLength = 524288;
            textEncoding.ReaderQuotas.MaxBytesPerRead = 16384;
            textEncoding.ReaderQuotas.MaxNameTableCharCount = 32768;

            var binding = new CustomBinding(securityElement, textEncoding, httpsTransport);
            binding.ReceiveTimeout = TimeSpan.FromMinutes(2);
            binding.SendTimeout = TimeSpan.FromMinutes(2);
            binding.OpenTimeout = TimeSpan.FromSeconds(30);
            binding.CloseTimeout = TimeSpan.FromSeconds(30);

            return binding;
        }

        /// <summary>
        /// Alternative binding using WSHttpBinding with strong security settings.
        /// </summary>
        public static WSHttpBinding CreateSecureWSHttpBinding()
        {
            var binding = new WSHttpBinding(SecurityMode.TransportWithMessageCredential)
            {
                MaxReceivedMessageSize = 1048576,
                MaxBufferPoolSize = 1048576,
                ReaderQuotas =
                {
                    MaxDepth = 32,
                    MaxStringContentLength = 524288,
                    MaxArrayLength = 524288,
                    MaxBytesPerRead = 16384,
                    MaxNameTableCharCount = 32768
                },
                ReceiveTimeout = TimeSpan.FromMinutes(2),
                SendTimeout = TimeSpan.FromMinutes(2)
            };

            // Transport security (TLS 1.2+)
            binding.Security.Transport.ClientCredentialType = HttpClientCredentialType.Certificate;

            // Message security with certificate authentication
            binding.Security.Message.ClientCredentialType = MessageCredentialType.Certificate;
            binding.Security.Message.EstablishSecurityContext = true;
            binding.Security.Message.NegotiateServiceCredential = false;

            // Use strong algorithm suite - AES-256 with SHA-256
            binding.Security.Message.AlgorithmSuite = SecurityAlgorithmSuite.Basic256Sha256;

            return binding;
        }
    }

