            string endpointAddress,
            string clientCertThumbprint,
            string serviceCertThumbprint,
            StoreLocation certStoreLocation = StoreLocation.LocalMachine)
        {
            if (string.IsNullOrWhiteSpace(endpointAddress))
                throw new ArgumentNullException(nameof(endpointAddress));
            if (string.IsNullOrWhiteSpace(clientCertThumbprint))
                throw new ArgumentNullException(nameof(clientCertThumbprint));
            if (string.IsNullOrWhiteSpace(serviceCertThumbprint))
                throw new ArgumentNullException(nameof(serviceCertThumbprint));

            var binding = SecureBindingFactory.CreateHipaaCompliantBinding();
            var endpointAddr = new EndpointAddress(
                new Uri(endpointAddress),
                EndpointIdentity.CreateX509CertificateIdentity(
                    FindCertificate(serviceCertThumbprint, certStoreLocation)));

            var factory = new ChannelFactory<IHealthcareRecordsService>(binding, endpointAddr);

            // Set client certificate
            factory.Credentials.ClientCertificate.SetCertificate(
                certStoreLocation,
                StoreName.My,
                X509FindType.FindByThumbprint,
                clientCertThumbprint);

            // Set expected service certificate for message encryption
            factory.Credentials.ServiceCertificate.SetDefaultCertificate(
                certStoreLocation,
                StoreName.TrustedPeople,
                X509FindType.FindByThumbprint,
                serviceCertThumbprint);

            // Validate service certificate chain
            factory.Credentials.ServiceCertificate.Authentication.CertificateValidationMode =
                System.ServiceModel.Security.X509CertificateValidationMode.ChainTrust;
            factory.Credentials.ServiceCertificate.Authentication.RevocationMode =
                X509RevocationMode.Online;

            return factory;
        }

        private static X509Certificate2 FindCertificate(string thumbprint, StoreLocation location)
        {
            using (var store = new X509Store(StoreName.My, location))
            {
                store.Open(OpenFlags.ReadOnly);
                var certs = store.Certificates.Find(X509FindType.FindByThumbprint, thumbprint, true);
                if (certs.Count == 0)
                    throw new InvalidOperationException($"Certificate with thumbprint {thumbprint} not found.");
                return certs[0];
            }
        }
    }

    // Encryption utility for data-at-rest protection of PHI
    public static class PhiEncryptionHelper
    {
        // In production, retrieve keys from a secure key vault (e.g., Azure Key Vault, AWS KMS, HSM)
        // Never store encryption keys in code, config files, or alongside encrypted data

        public static byte[] EncryptPhi(string plainText, byte[] key, out byte[] iv)
        {
            if (string.IsNullOrEmpty(plainText))
                throw new ArgumentNullException(nameof(plainText));
            if (key == null || key.Length != 32) // AES-256
                throw new ArgumentException("Key must be 256 bits (32 bytes).", nameof(key));

            using (var aes = Aes.Create())
            {
                aes.KeySize = 256;
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;
                aes.Key = key;
                aes.GenerateIV();
                iv = aes.IV;

                using (var encryptor = aes.CreateEncryptor())
                using (var ms = new MemoryStream())
                {
                    using (var cs = new CryptoStream(ms, encryptor, CryptoStreamMode.Write))
                    using (var writer = new StreamWriter(cs, System.Text.Encoding.UTF8))
                    {
                        writer.Write(plainText);
                    }
                    return ms.ToArray();
                }
            }
        }

        public static string DecryptPhi(byte[] cipherText, byte[] key, byte[] iv)
        {
            if (cipherText == null || cipherText.Length == 0)
                throw new ArgumentNullException(nameof(cipherText));
            if (key == null || key.Length != 32)
                throw new ArgumentException("Key must be 256 bits (32 bytes).", nameof(key));
            if (iv == null || iv.Length != 16)
                throw new ArgumentException("IV must be 128 bits (16 bytes).", nameof(iv));

            using (var aes = Aes.Create())
            {
                aes.KeySize = 256;
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;
                aes.Key = key;
                aes.IV = iv;

                using (var decryptor = aes.CreateDecryptor())
                using (var ms = new MemoryStream(cipherText))
                using (var cs = new CryptoStream(ms, decryptor, CryptoStreamMode.Read))
                using (var reader = new StreamReader(cs, System.Text.Encoding.UTF8))
                {
                    return reader.ReadToEnd();
                }
            }
        }

        /// <summary>
        /// Generates a cryptographically secure random key for AES-256.
        /// In production, use a key management service (KMS/HSM) instead.
        /// </summary>
        public static byte[] GenerateEncryptionKey()
        {
            var key = new byte[32]; // 256 bits
            using (var rng = RandomNumberGenerator.Create())
            {
                rng.GetBytes(key);
            }
            return key;
        }
    }

    // Program entry point demonstrating secure service hosting
    public class Program
    {
        public static void Main(string[] args)
        {
            // Certificate thumbprints should come from secure configuration (e.g., environment variables, key vault)
            // Never hardcode in source
            string serviceCertThumbprint = Environment.GetEnvironmentVariable("HEALTHCARE_SERVICE_CERT_THUMBPRINT");
            string baseAddress = Environment.GetEnvironmentVariable("HEALTHCARE_SERVICE_BASE_ADDRESS")
                                 ?? "https://localhost:8443/HealthcareService";

            if (string.IsNullOrWhiteSpace(serviceCertThumbprint))
            {
                Console.Error.WriteLine("ERROR: HEALTHCARE_SERVICE_CERT_THUMBPRINT environment variable is not set.");
                Environment.Exit(1);
                return;
            }

            ServiceHost host = null;
            try
            {
                host = SecureServiceHostFactory.CreateSecureServiceHost(
                    baseAddress,
                    serviceCertThumbprint);

                host.Open();
                Console.WriteLine($"HIPAA-compliant Healthcare Records Service started at {baseAddress}");
                Console.WriteLine("Security: WS-Security with mutual X.509 certificate authentication");
                Console.WriteLine("Encryption: AES-256 (message body), RSA-OAEP (key wrapping), SHA-256 (digest/signature)");
                Console.WriteLine("Press Enter to stop the service...");
                Console.ReadLine();
            }
            catch (Exception ex)
            {
                // Log error securely - do not expose certificate details or internal paths
                Console.Error.WriteLine($"Failed to start service: {ex.GetType().Name}");
                System.Diagnostics.Trace.TraceError($"Service startup failure: {ex}");
                Environment.Exit(1);
            }
            finally
            {
                if (host != null)
                {
                    try
                    {
                        if (host.State == CommunicationState.Opened)
                            host.Close();
                        else if (host.State == CommunicationState.Faulted)
                            host.Abort();
                    }
                    catch
                    {
                        host.Abort();
                    }
                }
            }
        }
    }
}